gold_sparql:
SELECT DISTINCT ?productionTime WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181020 ?domain .
  ?domain rdfs:label ?domainLabel .
  FILTER(LCASE(STR(?domainLabel)) = LCASE('automotive'))
  ?dataset orkgp:P181016 ?productionTime .
}

SELECT DISTINCT ?paper ?paperLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .
    ?contribution orkgp:P181046 ?implementedApproach .
    ?implementedApproach orkgp:release ?release .

    {
        ?release orkgp:P181049 ?releaseFormat .
        ?releaseFormat rdfs:label ?releaseFormatLabel .
        FILTER(LCASE(STR(?releaseFormatLabel)) != "not reported")
    }
    UNION
    {
        ?release orkgp:P181029 ?releaseLocationType .
        ?releaseLocationType rdfs:label ?releaseLocationTypeLabel .
        FILTER(LCASE(STR(?releaseLocationTypeLabel)) != "not reported")
    }

    FILTER NOT EXISTS {
        ?implementedApproach orkgp:P181027 ?licenseType .
        ?licenseType rdfs:label ?licenseTypeLabel .
        FILTER(LCASE(STR(?licenseTypeLabel)) != "not reported")
    }

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

SELECT DISTINCT ?domain ?domainLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181019 ?numSources ;
          orkgp:P181020 ?domain .
  OPTIONAL { ?domain rdfs:label ?domainLabel . }
  FILTER(xsd:integer(?numSources) >= 2)
}

SELECT DISTINCT ?paper ?paperLabel ?venue ?venueLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?contribution orkgp:P135046 ?venue .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?venue rdfs:label ?venueLabel . }
}
ORDER BY ?paperLabel ?venueLabel

SELECT DISTINCT ?year WHERE {
  ?paper orkgp:P31 ?contribution ;
    orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?annotationScheme .
  ?annotationScheme orkgp:P181038 ?guidelineAvailability .
  ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel .
  FILTER(LCASE(STR(?guidelineAvailabilityLabel)) = LCASE("yes"))
}

SELECT DISTINCT ?year
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?paper orkgp:P29 ?year .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentionedThreat .
  FILTER(LCASE(STR(?mentionedThreat)) IN ("true", "yes", "1"))
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?anyConstructValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?anyInternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?anyExternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?anyConclusionValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?anyReliability . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?anyGeneralizability . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?anyRepeatability . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?anyContentValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?anyDescriptiveValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?anyTheoreticalValidity . }
}
ORDER BY ?year

SELECT DISTINCT ?domainLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181020 ?domain .
  OPTIONAL { ?domain rdfs:label ?domainLabel . }
}
ORDER BY ?domainLabel

SELECT ?year (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P37330 ?research_question .

    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year
ORDER BY ?year

SELECT DISTINCT ?paper ?paperLabel
WHERE {
    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P37330 ?research_question .

    ?venue rdfs:label ?venue_name .

    ?research_question orkgp:P41928 ?question_type .

    ?research_question orkgp:P57000 ?subquestion1 ;
                       orkgp:P57000 ?subquestion2 .

    FILTER(?subquestion1 != ?subquestion2)

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  { ?contribution orkgp:P15124 ?dataAnalysis . ?dataAnalysis orkgp:P56048 ?descriptiveStatistic . }
  UNION
  { ?contribution orkgp:P15124 ?dataAnalysis . ?dataAnalysis orkgp:P57016 ?machineLearning . }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

SELECT DISTINCT ?approachType ?approachTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?approach orkgp:P5043 ?approachType .
  OPTIONAL { ?approachType rdfs:label ?approachTypeLabel . }
  ?evaluation orkgp:P110006 ?metric .
  ?metric rdfs:label ?metricLabel .
  FILTER(LCASE(STR(?metricLabel)) = LCASE('precision'))
}

SELECT DISTINCT ?productionTime WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181021 ?abstractionLevel .
  ?abstractionLevel rdfs:label ?abstractionLevelLabel .
  FILTER(CONTAINS(LCASE(STR(?abstractionLevelLabel)), 'token-level'))
  ?dataset orkgp:P181016 ?productionTime .
}

SELECT (COUNT(DISTINCT ?paper) AS ?count)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  ?contribution orkgp:P37330 ?researchQuestion .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  FILTER NOT EXISTS { ?contribution orkgp:P57004 ?anyResearchQuestionAnswer . }
}

SELECT DISTINCT (COALESCE(?establishmentLabel, STR(?establishment)) AS ?establishmentValue) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181032 ?annotator ;
    orkgp:P181036 ?annotationScheme .
  ?annotator orkgp:P59120 ?numAnnotators .
  FILTER(?numAnnotators = 2)
  ?annotationScheme orkgp:P181037 ?establishment .
  OPTIONAL { ?establishment rdfs:label ?establishmentLabel . }
}

SELECT ?year ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?rq_flag) AS ?has_rq)
               (MAX(?rqa_flag) AS ?has_rqa)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue .

            ?venue rdfs:label ?venue_name .

            OPTIONAL {
                ?contribution orkgp:P37330 ?research_question .
                BIND(1 AS ?rq_flag)
            }

            OPTIONAL {
                ?contribution orkgp:P57004 ?research_question_answer .
                BIND(1 AS ?rqa_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }

    BIND(
        IF(?has_rq = 1 && ?has_rqa = 1, "both reported"^^xsd:string,
            IF(?has_rq = 1 && (!BOUND(?has_rqa) || ?has_rqa != 1), "only research question reported"^^xsd:string,
                IF((!BOUND(?has_rq) || ?has_rq != 1) && ?has_rqa = 1, "only research question answer reported"^^xsd:string,
                    "neither reported"^^xsd:string
                )
            )
        ) AS ?reporting_case
    )
}
GROUP BY ?year ?reporting_case
ORDER BY ?year ?reporting_case

SELECT ?paper ?paperLabel (COUNT(DISTINCT ?url) AS ?number_of_reported_urls)
WHERE {

    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P56008 ?data_collection .

    ?venue rdfs:label ?venue_name .

    ?data_collection rdfs:label ?dc_label ;
                     orkgp:DATA ?research_data .

    ?research_data orkgp:url ?url .

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?number_of_reported_urls) ?paperLabel

SELECT DISTINCT ?year WHERE {
