SELECT ?paper ?paperLabel (COUNT(DISTINCT ?method_type) AS ?number_of_different_reported_method_types)
WHERE {

    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P56008 ?data_collection .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?venue rdfs:label ?venue_name .

    ?data_collection rdfs:label ?dc_label ;
                     orkgp:P1005 ?dc_method .

    ?dc_method orkgp:P94003 ?method_type .

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?number_of_different_reported_method_types) ?paperLabel

SELECT DISTINCT ?paper ?paperLabel
WHERE {
    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    {
        ?contribution orkgp:P37330 ?research_question .
        ?research_question orkgp:P41928 ?rq_question_type .
    }
    UNION
    {
        ?contribution orkgp:P37330 ?research_question .
        ?research_question orkgp:P57000 ?subquestion .
        ?subquestion orkgp:P41928 ?subquestion_type .
    }

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel

SELECT ?paper ?paperLabel (COUNT(DISTINCT ?hypothesis) AS ?number_of_reported_hypotheses)
WHERE {

    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P15124 ?data_analysis .

    ?venue rdfs:label ?venue_name .

    ?data_analysis rdfs:label ?da_label ;
                   orkgp:P56043 ?inferential_statistics .

    ?inferential_statistics orkgp:P30001 ?hypothesis .

    FILTER(?da_label != "no analysis"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?number_of_reported_hypotheses) ?paperLabel

SELECT DISTINCT ?paper ?paperLabel WHERE {
