SELECT ?year (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P37330 ?research_question .

    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year
ORDER BY ?year

SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .
  ?contribution orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181041 ?agreement .
  ?agreement orkgp:P181042 ?metric .
  ?agreement orkgp:P181044 ?conflictResolution .
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

SELECT ?decade ?ml_algorithm ?ml_algorithmLabel (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P15124 ?data_analysis .

    ?venue rdfs:label ?venue_name .

    ?data_analysis rdfs:label ?da_label ;
                   orkgp:P57016 ?machine_learning .

    ?machine_learning orkgp:P2001 ?ml_algorithm .

    OPTIONAL { ?ml_algorithm rdfs:label ?ml_algorithmLabel . }

    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

    FILTER(?da_label != "no analysis"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?decade ?ml_algorithm ?ml_algorithmLabel
ORDER BY ?decade DESC(?paper_count) ?ml_algorithmLabel

SELECT DISTINCT ?paper ?paperLabel ?baselineTypeLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181051 ?baselineComparison .
  ?baselineComparison orkgp:P181052 ?baselineType .
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?baselineType rdfs:label ?baselineTypeLabel . }
}
ORDER BY ?paperLabel ?baselineTypeLabel

SELECT DISTINCT ?numDataItems WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181028 ?location .
  ?location orkgp:P181030 ?locationType .
  ?locationType rdfs:label ?locationTypeLabel .
  FILTER(LCASE(STR(?locationTypeLabel)) = LCASE('zenodo'))
  ?dataset orkgp:P181015 ?numDataItems .
}

ASK {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue .
  ?venue rdfs:label ?venue_name .

  ?contribution orkgp:P57004 ?researchQuestionAnswer .
  ?researchQuestionAnswer orkgp:P55039 ?highlightedInText .
  FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}

SELECT (COUNT(DISTINCT ?contribution) AS ?numContributions) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181051 ?baselineComparison ;
    orkgp:P110006 ?metric .
  ?metric rdfs:label ?metricLabel .
  FILTER(LCASE(STR(?metricLabel)) = LCASE('accuracy'))
}

SELECT (MIN(xsd:integer(STR(?year))) AS ?earliestYear)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?paper orkgp:P29 ?year .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentionedThreat .
  FILTER(LCASE(STR(?mentionedThreat)) IN ("true", "yes", "1"))
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?anyConstructValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?anyInternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?anyExternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?anyConclusionValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?anyReliability . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?anyGeneralizability . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?anyRepeatability . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?anyContentValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?anyDescriptiveValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?anyTheoreticalValidity . }
}

SELECT DISTINCT ?paper ?paperLabel ?year WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?paper orkgp:P29 ?year .
  ?contribution orkgp:P181011 ?dataset .
  ?dataset orkgp:license ?license .
  ?license orkgp:P181026 ?publicAvailability .
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel ?year

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  ?contribution orkgp:P56008 ?dataCollection .
  ?dataCollection orkgp:P1005 ?dataCollectionMethod .
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  FILTER NOT EXISTS { ?dataCollectionMethod orkgp:P94003 ?anyMethodType . }
}
ORDER BY ?paperLabel

SELECT DISTINCT (COALESCE(?dependencyLabel, STR(?dependency)) AS ?dependencyValue) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach .
  ?approach orkgp:release ?release ;
    orkgp:P181048 ?dependency .
  ?release orkgp:P1003 ?url .
  FILTER(CONTAINS(LCASE(STR(?url)), 'github'))
  OPTIONAL { ?dependency rdfs:label ?dependencyLabel . }
}

SELECT DISTINCT ?year
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?paper orkgp:P29 ?year .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentionedThreat .
  FILTER(LCASE(STR(?mentionedThreat)) IN ("true", "yes", "1"))
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?anyConstructValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?anyInternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?anyExternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?anyConclusionValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?anyReliability . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?anyGeneralizability . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?anyRepeatability . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?anyContentValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?anyDescriptiveValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?anyTheoreticalValidity . }
}
ORDER BY ?year

SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .
  ?contribution orkgp:P181011 ?dataset .
  ?dataset orkgp:P181028 ?datasetLocation .
  FILTER NOT EXISTS { ?datasetLocation orkgp:P1003 ?datasetUrl . }
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

SELECT DISTINCT ?taskType ?taskTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset ;
    orkgp:P181003 ?nlpTask .
  ?dataset rdfs:label ?datasetLabel .
  FILTER(LCASE(STR(?datasetLabel)) = LCASE('conll-2003'))
  ?nlpTask orkgp:P181004 ?taskType .
  OPTIONAL { ?taskType rdfs:label ?taskTypeLabel . }
}

SELECT DISTINCT ?productionTime WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181019 ?numSources .
  FILTER(?numSources > 1)
  ?dataset orkgp:P181016 ?productionTime .
}

SELECT DISTINCT ?paper ?paperLabel ?agreement WHERE {
  {
    SELECT ?paper (MAX(xsd:decimal(?a)) AS ?agreement) WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 .
      ?contribution orkgp:P181031 ?annotationProcess .
      ?annotationProcess orkgp:P181041 ?agreementStmt .
      ?agreementStmt orkgp:P181045 ?a .
    }
    GROUP BY ?paper
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY DESC(?agreement)

SELECT DISTINCT ?year WHERE {
  ?paper orkgp:P31 ?contribution ;
    orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?annotationScheme .
  ?annotationScheme orkgp:P181037 ?establishment .
  ?establishment rdfs:label ?establishmentLabel .
  FILTER(CONTAINS(LCASE(STR(?establishmentLabel)), 'consensus'))
}

SELECT DISTINCT ?reliabilityMetric ?reliabilityMetricLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181041 ?annotatorAgreement .
  ?annotatorAgreement orkgp:P181044 ?conflictResolution ;
    orkgp:P181042 ?reliabilityMetric .
  ?conflictResolution rdfs:label ?conflictResolutionLabel .
  FILTER(CONTAINS(LCASE(STR(?conflictResolutionLabel)), 'majority vote'))
  OPTIONAL { ?reliabilityMetric rdfs:label ?reliabilityMetricLabel . }
}

SELECT
  ?approachType
  ?approachTypeLabel
  ?algorithm
  ?algorithmLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?approachType
      ?algorithm
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .

      ?implementedApproach orkgp:P5043 ?approachType ;
                           orkgp:P58069 ?algorithm .
    }
    GROUP BY ?approachType ?algorithm
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?approachType2
          ?algorithm2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181046 ?implementedApproach2 .

          ?implementedApproach2 orkgp:P5043 ?approachType2 ;
                                orkgp:P58069 ?algorithm2 .
        }
        GROUP BY ?approachType2 ?algorithm2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181046 ?implementedApproach .
  ?implementedApproach orkgp:P5043 ?approachType ;
                       orkgp:P58069 ?algorithm .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?approachType rdfs:label ?approachTypeLabel . }
  OPTIONAL { ?algorithm rdfs:label ?algorithmLabel . }
}
GROUP BY
  ?approachType ?approachTypeLabel
  ?algorithm ?algorithmLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?approachTypeLabel ?algorithmLabel

SELECT (COUNT(DISTINCT ?contribution) AS ?numContributions) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181022 ?dataType .
  ?dataType orkgp:P181025 ?naturalLanguage ;
    orkgp:P181023 ?dataFormat .
  ?naturalLanguage rdfs:label ?naturalLanguageLabel .
  FILTER(LCASE(STR(?naturalLanguageLabel)) = LCASE('english'))
  ?dataFormat rdfs:label ?dataFormatLabel .
  FILTER(CONTAINS(LCASE(STR(?dataFormatLabel)), 'token-level'))
}

SELECT DISTINCT ?guidelineAvailabilityLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?scheme .
  ?scheme orkgp:P181038 ?guidelineAvailability .
  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
}
ORDER BY ?guidelineAvailabilityLabel

SELECT DISTINCT ?guidelineAvailabilityLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?scheme .
  ?scheme orkgp:P181038 ?guidelineAvailability .
  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
}
ORDER BY ?guidelineAvailabilityLabel

SELECT DISTINCT ?taskType ?taskTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181003 ?nlpTask ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?nlpTask orkgp:P181004 ?taskType .
  ?evaluation orkgp:P110006 ?metric .
  ?metric rdfs:label ?metricLabel .
  OPTIONAL { ?taskType rdfs:label ?taskTypeLabel . }
  FILTER(CONTAINS(LCASE(STR(?metricLabel)), "f1"))
}

SELECT
  ?sourceType
  ?sourceTypeLabel
  ?sourceDomain
  ?sourceDomainLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?sourceType
      ?sourceDomain
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181011 ?dataset .

      ?dataset orkgp:P181017 ?dataSource .

      ?dataSource orkgp:P181018 ?sourceType ;
                  orkgp:P181020 ?sourceDomain .
    }
    GROUP BY ?sourceType ?sourceDomain
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?sourceType2
          ?sourceDomain2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181011 ?dataset2 .

          ?dataset2 orkgp:P181017 ?dataSource2 .

          ?dataSource2 orkgp:P181018 ?sourceType2 ;
                       orkgp:P181020 ?sourceDomain2 .
        }
        GROUP BY ?sourceType2 ?sourceDomain2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?dataSource .
  ?dataSource orkgp:P181018 ?sourceType ;
              orkgp:P181020 ?sourceDomain .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?sourceType rdfs:label ?sourceTypeLabel . }
  OPTIONAL { ?sourceDomain rdfs:label ?sourceDomainLabel . }
}
GROUP BY
  ?sourceType ?sourceTypeLabel
  ?sourceDomain ?sourceDomainLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?sourceTypeLabel ?sourceDomainLabel

SELECT ?data_type ?data_typeLabel ?method_type ?method_typeLabel
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P56008 ?data_collection .

    ?venue rdfs:label ?venue_name .

    ?data_collection rdfs:label ?dc_label ;
                     orkgp:DATA ?research_data ;
                     orkgp:P1005 ?dc_method .

    ?research_data orkgp:P7055 ?data_type .

    ?dc_method orkgp:P94003 ?method_type .

    OPTIONAL { ?data_type rdfs:label ?data_typeLabel . }
    OPTIONAL { ?method_type rdfs:label ?method_typeLabel . }

    FILTER(?dc_label != "no collection"^^xsd:string)

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}

GROUP BY ?data_type ?data_typeLabel ?method_type ?method_typeLabel

ORDER BY DESC(?paper_count) ?data_typeLabel ?method_typeLabel

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P15124 ?dataAnalysis .
  ?dataAnalysis orkgp:P56048 ?descriptiveStatistic .
  ?descriptiveStatistic orkgp:P57005 ?centralTendency .
  { ?centralTendency orkgp:P47000 ?mean . FILTER(LCASE(STR(?mean)) IN ("true", "yes", "1")) }
  UNION
  { ?centralTendency orkgp:P57006 ?median . FILTER(LCASE(STR(?median)) IN ("true", "yes", "1")) }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

SELECT (COUNT(DISTINCT ?contribution) AS ?numContributions) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181051 ?baselineComparison ;
    orkgp:P110006 ?metric .
  ?metric rdfs:label ?metricLabel .
  FILTER(LCASE(STR(?metricLabel)) = LCASE('accuracy'))
}

SELECT DISTINCT ?domainLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181020 ?domain .
  OPTIONAL { ?domain rdfs:label ?domainLabel . }
}
ORDER BY ?domainLabel

SELECT DISTINCT ?numSources WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181020 ?domain .
  ?domain rdfs:label ?domainLabel .
  FILTER(LCASE(STR(?domainLabel)) = LCASE('information systems'))
  ?source orkgp:P181019 ?numSources .
}

SELECT ?research_paradigm ?research_paradigmLabel
       (COUNT(DISTINCT ?paper) AS ?total_papers)
       (SUM(?has_rqa_highlighted) AS ?papers_with_rqa_highlighted)
       ((100.0 * SUM(?has_rqa_highlighted)) / COUNT(DISTINCT ?paper) AS ?percentage_with_rqa_highlighted)
WHERE {
    {
        SELECT ?paper ?research_paradigm ?research_paradigmLabel
               (MAX(?rqa_highlighted_flag) AS ?has_rqa_highlighted)
        WHERE {
            ?paper orkgp:P31 ?contribution .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm .

            ?venue rdfs:label ?venue_name .

            OPTIONAL { ?research_paradigm rdfs:label ?research_paradigmLabel . }

            OPTIONAL {
                ?contribution orkgp:P57004 ?research_question_answer .
                ?research_question_answer orkgp:P55039 ?rqa_highlighted_in_text .
                BIND(1 AS ?rqa_highlighted_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?research_paradigm ?research_paradigmLabel
    }
}
GROUP BY ?research_paradigm ?research_paradigmLabel
ORDER BY DESC(?percentage_with_rqa_highlighted) ?research_paradigmLabel

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P15124 ?dataAnalysis .
  { ?dataAnalysis orkgp:P56043 ?inferentialStatistics . ?inferentialStatistics orkgp:P35133 ?statisticalTechnique . }
  UNION
  { ?dataAnalysis orkgp:P57016 ?machineLearning . ?machineLearning orkgp:P2001 ?algorithm . }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

SELECT ?year ?question_type ?question_typeLabel (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P37330 ?research_question .

    ?venue rdfs:label ?venue_name .

    ?research_question orkgp:P41928 ?question_type .

    OPTIONAL { ?question_type rdfs:label ?question_typeLabel . }

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year ?question_type ?question_typeLabel
ORDER BY ?year DESC(?paper_count) ?question_typeLabel

SELECT ?decade ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
  {
    SELECT ?paper ?decade
           (MAX(?is_flag) AS ?has_is)
           (MAX(?ml_flag) AS ?has_ml)
    WHERE {
      ?paper orkgp:P31 ?contribution ;
             orkgp:P29 ?year .

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue ;
                    orkgp:P15124 ?data_analysis .

      ?venue rdfs:label ?venue_name .
      ?data_analysis rdfs:label ?da_label .

      BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
      BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

      OPTIONAL {
        ?data_analysis orkgp:P56043 ?inferential_statistics .
        BIND(1 AS ?is_flag)
      }

      OPTIONAL {
        ?data_analysis orkgp:P57016 ?machine_learning .
        BIND(1 AS ?ml_flag)
      }

      FILTER(?da_label != "no analysis"^^xsd:string)
      FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    }
    GROUP BY ?paper ?decade
  }

  BIND(
    IF(?has_is = 1 && ?has_ml = 1, "both"^^xsd:string,
      IF(?has_is = 1 && (!BOUND(?has_ml) || ?has_ml != 1), "inferential-statistics only"^^xsd:string,
        IF((!BOUND(?has_is) || ?has_is != 1) && ?has_ml = 1, "machine-learning only"^^xsd:string,
          "neither"^^xsd:string
        )
      )
    ) AS ?reporting_case
  )
}
GROUP BY ?decade ?reporting_case
ORDER BY ?decade ?reporting_case

SELECT ?research_paradigm ?research_paradigmLabel (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {

    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P57003 ?research_paradigm .

    ?venue rdfs:label ?venue_name .
    ?research_paradigm rdfs:label ?research_paradigmLabel .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?research_paradigm ?research_paradigmLabel
ORDER BY DESC(?paper_count)

SELECT ?publicationDecade ?validationProcedureLabel ?paperCount
        (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  {
    SELECT ?publicationDecade ?validationProcedureLabel ?paperCount
    WHERE {
      {
        SELECT ?publicationDecade ?validationProcedureLabel (COUNT(DISTINCT ?paper) AS ?paperCount)
        WHERE {
            ?paper orkgp:P31 ?contribution .
            ?paper orkgp:P29 ?year .
            ?contribution a orkgc:C121001 .

            ?contribution orkgp:HAS_EVALUATION ?evaluation .
            ?evaluation orkgp:P181050 ?validationProcedure .
            ?validationProcedure rdfs:label ?validationProcedureLabel .

            FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
            FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart)
            BIND(CONCAT(STR(?decadeStart), "s") AS ?publicationDecade)
        }
          GROUP BY ?publicationDecade ?validationProcedureLabel
      }

      {
        SELECT ?publicationDecade (MAX(?cnt) AS ?maxCount)
        WHERE {
          {
            SELECT ?publicationDecade ?validationProcedureLabel (COUNT(DISTINCT ?paper) AS ?cnt)
            WHERE {
                ?paper orkgp:P31 ?contribution .
                ?paper orkgp:P29 ?year .
                ?contribution a orkgc:C121001 .

                ?contribution orkgp:HAS_EVALUATION ?evaluation .
                ?evaluation orkgp:P181050 ?validationProcedure .
                ?validationProcedure rdfs:label ?validationProcedureLabel .

                FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
                FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

                BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart)
                BIND(CONCAT(STR(?decadeStart), "s") AS ?publicationDecade)
              }
              GROUP BY ?publicationDecade ?validationProcedureLabel
          }
        }
        GROUP BY ?publicationDecade
      }

      FILTER(?paperCount = ?maxCount)
    }
  }

    ?paper orkgp:P31 ?contribution .
    ?paper orkgp:P29 ?year .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181050 ?validationProcedure .
    ?validationProcedure rdfs:label ?validationProcedureLabel .

    FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
    FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart2)
    BIND(CONCAT(STR(?decadeStart2), "s") AS ?publicationDecade)

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
GROUP BY ?publicationDecade ?validationProcedureLabel ?paperCount
ORDER BY ?publicationDecade ?validationProcedureLabel

