SELECT DISTINCT ?paper ?paperLabel ?categoryCount
WHERE {
  {
    SELECT ?paper (COUNT(DISTINCT ?category) AS ?categoryCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C27001 .
      ?contribution orkgp:P135046 ?venue .
      ?venue rdfs:label ?venueName .
      FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
      ?contribution orkgp:P15124 ?dataAnalysis .
      ?dataAnalysis orkgp:P56048 ?descriptiveStatistic .
      {
        ?descriptiveStatistic orkgp:P56049 ?frequencyMeasure .
        BIND("frequency" AS ?category)
      }
      UNION
      {
        ?descriptiveStatistic orkgp:P57005 ?centralTendency .
        BIND("central_tendency" AS ?category)
      }
      UNION
      {
        ?descriptiveStatistic orkgp:P57008 ?dispersionVariation .
        BIND("dispersion_variation" AS ?category)
      }
      UNION
      {
        ?descriptiveStatistic orkgp:P57010 ?positionMeasure .
        BIND("position" AS ?category)
      }
    }
    GROUP BY ?paper
  }
  {
    SELECT (MAX(?innerCategoryCount) AS ?maxCategoryCount)
    WHERE {
      {
        SELECT ?innerPaper (COUNT(DISTINCT ?innerCategory) AS ?innerCategoryCount)
        WHERE {
          ?innerPaper orkgp:P31 ?innerContribution .
          ?innerContribution a orkgc:C27001 .
          ?innerContribution orkgp:P135046 ?innerVenue .
          ?innerVenue rdfs:label ?innerVenueName .
          FILTER(LCASE(STR(?innerVenueName)) = LCASE("IEEE International Requirements Engineering Conference"))
          ?innerContribution orkgp:P15124 ?innerDataAnalysis .
          ?innerDataAnalysis orkgp:P56048 ?innerDescriptiveStatistic .
          {
            ?innerDescriptiveStatistic orkgp:P56049 ?innerFrequencyMeasure .
            BIND("frequency" AS ?innerCategory)
          }
          UNION
          {
            ?innerDescriptiveStatistic orkgp:P57005 ?innerCentralTendency .
            BIND("central_tendency" AS ?innerCategory)
          }
          UNION
          {
            ?innerDescriptiveStatistic orkgp:P57008 ?innerDispersionVariation .
            BIND("dispersion_variation" AS ?innerCategory)
          }
          UNION
          {
            ?innerDescriptiveStatistic orkgp:P57010 ?innerPositionMeasure .
            BIND("position" AS ?innerCategory)
          }
        }
        GROUP BY ?innerPaper
      }
    }
  }
  FILTER(?categoryCount = ?maxCategoryCount)
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

