SELECT ?venue ?venue_name ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
  {
    SELECT ?paper ?venue ?venue_name
           (MAX(?hidden_flag) AS ?has_hidden)
           (MAX(?highlighted_flag) AS ?has_highlighted)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

      ?venue rdfs:label ?venue_name .

      OPTIONAL {
        ?contribution orkgp:P37330 ?rq_hidden .
        ?rq_hidden orkgp:P55038 ?hidden_value .
        BIND(1 AS ?hidden_flag)
      }

      OPTIONAL {
        ?contribution orkgp:P37330 ?rq_highlighted .
        ?rq_highlighted orkgp:P55039 ?highlighted_value .
        BIND(1 AS ?highlighted_flag)
      }
    }
    GROUP BY ?paper ?venue ?venue_name
  }

  BIND(
    IF(?has_hidden = 1 && ?has_highlighted = 1, "both hidden and highlighted"^^xsd:string,
      IF(?has_hidden = 1 && (!BOUND(?has_highlighted) || ?has_highlighted != 1), "hidden only"^^xsd:string,
        IF((!BOUND(?has_hidden) || ?has_hidden != 1) && ?has_highlighted = 1, "highlighted only"^^xsd:string,
          "neither flag reported"^^xsd:string
        )
      )
    ) AS ?reporting_case
  )
}
GROUP BY ?venue ?venue_name ?reporting_case
ORDER BY ?venue_name ?reporting_case

