  ?dataType orkgp:P181025 ?naturalLanguage .
  ?naturalLanguage rdfs:label ?naturalLanguageLabel .
  FILTER(LCASE(STR(?naturalLanguageLabel)) = LCASE('english'))
  ?dataset orkgp:P181017 ?source .
  ?source orkgp:P181020 ?domain .
  OPTIONAL { ?domain rdfs:label ?domainLabel . }
}

SELECT DISTINCT ?metricLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P110006 ?metric .
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}
ORDER BY ?metricLabel

SELECT ?year
       (COUNT(DISTINCT ?paper) AS ?papers_with_research_question)
       (SUM(?has_subquestion) AS ?papers_with_at_least_one_subquestion)
       ((COUNT(DISTINCT ?paper) - SUM(?has_subquestion)) AS ?papers_without_subquestion)
       ((100.0 * SUM(?has_subquestion)) / COUNT(DISTINCT ?paper) AS ?percentage_with_subquestion)
       ((100.0 * (COUNT(DISTINCT ?paper) - SUM(?has_subquestion))) / COUNT(DISTINCT ?paper) AS ?percentage_without_subquestion)
WHERE {
    {
        SELECT ?paper ?year (MAX(?subquestion_flag) AS ?has_subquestion)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P37330 ?research_question .

            ?venue rdfs:label ?venue_name .

            OPTIONAL {
                ?research_question orkgp:P57000 ?subquestion .
                BIND(1 AS ?subquestion_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT DISTINCT ?mentionedThreat
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentionedThreat .
  FILTER(LCASE(STR(?mentionedThreat)) IN ("true", "yes", "1"))
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?anyConstructValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?anyInternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?anyExternalValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?anyConclusionValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?anyReliability . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?anyGeneralizability . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?anyRepeatability . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?anyContentValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?anyDescriptiveValidity . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?anyTheoreticalValidity . }
}
ORDER BY ?mentionedThreat

SELECT
  ?sourceType
  ?sourceTypeLabel
  ?sourceDomain
  ?sourceDomainLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?sourceType
      ?sourceDomain
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181011 ?dataset .

      ?dataset orkgp:P181017 ?dataSource .

      ?dataSource orkgp:P181018 ?sourceType ;
                  orkgp:P181020 ?sourceDomain .
    }
    GROUP BY ?sourceType ?sourceDomain
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?sourceType2
          ?sourceDomain2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181011 ?dataset2 .

          ?dataset2 orkgp:P181017 ?dataSource2 .

          ?dataSource2 orkgp:P181018 ?sourceType2 ;
                       orkgp:P181020 ?sourceDomain2 .
        }
        GROUP BY ?sourceType2 ?sourceDomain2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?dataSource .
  ?dataSource orkgp:P181018 ?sourceType ;
              orkgp:P181020 ?sourceDomain .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?sourceType rdfs:label ?sourceTypeLabel . }
  OPTIONAL { ?sourceDomain rdfs:label ?sourceDomainLabel . }
}
GROUP BY
  ?sourceType ?sourceTypeLabel
  ?sourceDomain ?sourceDomainLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?sourceTypeLabel ?sourceDomainLabel

SELECT (COUNT(DISTINCT ?contribution) AS ?count) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?scheme .
  ?scheme orkgp:P181038 ?guidelineAvailability .
  FILTER(CONTAINS(LCASE(STR(COALESCE(?guidelineAvailability, STR(?guidelineAvailability)))), "public"))
}

SELECT DISTINCT ?documentationType ?documentationTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach .
  ?approach orkgp:P58069 ?algorithm ;
    orkgp:P41835 ?documentationType .
  ?algorithm rdfs:label ?algorithmLabel .
  FILTER(CONTAINS(LCASE(STR(?algorithmLabel)), 'neural network'))
  OPTIONAL { ?documentationType rdfs:label ?documentationTypeLabel . }
}

SELECT DISTINCT ?outputType ?outputTypeLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181003 ?nlpTask .
  ?nlpTask orkgp:P181006 ?output .
  ?output orkgp:P181008 ?classificationLabel ;
    orkgp:P181007 ?outputType .
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}

SELECT (COUNT(DISTINCT ?contribution) AS ?count) WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P110006 ?metric ;
              orkgp:P181050 ?validationProcedure .
}

SELECT (COUNT(DISTINCT ?paper) AS ?count)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P135046 ?venue .
  ?venue rdfs:label ?venueName .
  ?contribution orkgp:P37330 ?researchQuestion .
  FILTER(LCASE(STR(?venueName)) = LCASE("IEEE International Requirements Engineering Conference"))
  FILTER NOT EXISTS { ?contribution orkgp:P57004 ?anyResearchQuestionAnswer . }
}

SELECT DISTINCT ?year WHERE {
  ?paper orkgp:P31 ?contribution ;
    orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181050 ?validationProcedure ;
    orkgp:P110006 ?metric .
  ?validationProcedure rdfs:label ?validationProcedureLabel .
  FILTER(LCASE(STR(?validationProcedureLabel)) = LCASE('cross-validation'))
  ?metric rdfs:label ?metricLabel .
  FILTER(CONTAINS(LCASE(STR(?metricLabel)), 'f1'))
}

SELECT DISTINCT ?validationProcedureLabel WHERE {
  ?contribution a orkgc:C121001 .
  ?paper orkgp:P31 ?contribution .
  ?contribution orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181050 ?validationProcedure .
  OPTIONAL { ?validationProcedure rdfs:label ?validationProcedureLabel . }
}
ORDER BY ?validationProcedureLabel

SELECT DISTINCT ?releaseFormat ?releaseFormatLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach .
  ?approach orkgp:release ?release .
  ?release orkgp:P1003 ?url ;
    orkgp:P181049 ?releaseFormat .
  FILTER(CONTAINS(LCASE(STR(?url)), 'github'))
  OPTIONAL { ?releaseFormat rdfs:label ?releaseFormatLabel . }
}

SELECT ?year (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT ?paper ?year (COUNT(DISTINCT ?category) AS ?category_count)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm ;
                          orkgp:P39099 ?threats .

            ?venue rdfs:label ?venue_name .

            {
                ?threats orkgp:P55037 ?v .
                BIND("construct validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P55035 ?v .
                BIND("internal validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P55034 ?v .
                BIND("external validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P55036 ?v .
                BIND("conclusion validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P59109 ?v .
                BIND("reliability"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P60006 ?v .
                BIND("generalizability"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P97002 ?v .
                BIND("repeatability"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P68005 ?v .
                BIND("content validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P97000 ?v .
                BIND("descriptive validity"^^xsd:string AS ?category)
            }
            UNION
            {
                ?threats orkgp:P97001 ?v .
                BIND("theoretical validity"^^xsd:string AS ?category)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
        HAVING(COUNT(DISTINCT ?category) >= 10)
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT ?paper ?paperLabel (COUNT(DISTINCT ?url) AS ?number_of_reported_urls)
WHERE {

    ?paper orkgp:P31 ?contribution .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P56008 ?data_collection .

    ?venue rdfs:label ?venue_name .

    ?data_collection rdfs:label ?dc_label ;
                     orkgp:DATA ?research_data .

    ?research_data orkgp:url ?url .

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?number_of_reported_urls) ?paperLabel

SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .
  ?contribution orkgp:P181003 ?nlpTask .
  ?nlpTask orkgp:P181006 ?output .
  ?output orkgp:P181007 ?outputType .
  ?output orkgp:P181010 ?mappingCardinality .
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

SELECT ?year
       (SUM(?has_both_highlighted) AS ?papers_with_both_highlighted)
       (SUM(?has_both_highlighted_and_data_url_and_threats_mentioned) AS ?papers_with_both_highlighted_and_also_data_url_and_threats_mentioned)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?both_highlighted_flag) AS ?has_both_highlighted)
               (MAX(?all_conditions_flag) AS ?has_both_highlighted_and_data_url_and_threats_mentioned)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue .

            ?venue rdfs:label ?venue_name .

            ?contribution orkgp:P37330 ?research_question .
            ?research_question orkgp:P55039 ?rq_highlighted .

            ?contribution orkgp:P57004 ?research_question_answer .
            ?research_question_answer orkgp:P55039 ?rqa_highlighted .

            BIND(1 AS ?both_highlighted_flag)

            OPTIONAL {
                ?contribution orkgp:P56008 ?data_collection ;
                              orkgp:P39099 ?threats .

                ?data_collection rdfs:label ?dc_label ;
                                 orkgp:DATA ?research_data .

                ?research_data orkgp:url ?url .
                ?threats orkgp:P145000 ?mentioned .

                FILTER(?dc_label != "no collection"^^xsd:string)

                BIND(1 AS ?all_conditions_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT DISTINCT ?licenseTypeText WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach .
  ?approach orkgp:release ?release ;
           orkgp:P181027 ?licenseType .
  ?release orkgp:P181029 ?locationType .
  ?locationType rdfs:label ?locationTypeLabel .
  FILTER(CONTAINS(LCASE(STR(?locationTypeLabel)), "repository") || CONTAINS(LCASE(STR(?locationTypeLabel)), "github"))
  OPTIONAL { ?licenseType rdfs:label ?licenseTypeLabel . }
  BIND(COALESCE(?licenseTypeLabel, STR(?licenseType)) AS ?licenseTypeText)
}

SELECT DISTINCT ?year WHERE {
  ?paper orkgp:P31 ?contribution ;
    orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181036 ?annotationScheme .
  ?annotationScheme orkgp:P181038 ?guidelineAvailability .
  ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel .
  FILTER(LCASE(STR(?guidelineAvailabilityLabel)) = LCASE("yes"))
}

SELECT ?decade ?data_type ?data_typeLabel
       ?research_paradigm ?research_paradigmLabel
       ?method_type ?method_typeLabel
       ?paper_count
WHERE {
    {
        SELECT ?decade ?data_type ?data_typeLabel (MAX(?paper_count) AS ?max_paper_count)
        WHERE {
            {
                SELECT ?decade ?data_type ?data_typeLabel
                       ?research_paradigm ?research_paradigmLabel
                       ?method_type ?method_typeLabel
                       (COUNT(DISTINCT ?paper) AS ?paper_count)
                WHERE {
                    ?paper orkgp:P31 ?contribution ;
                           orkgp:P29 ?year .

                    ?contribution a orkgc:C27001 ;
                                  orkgp:P135046 ?venue ;
                                  orkgp:P57003 ?research_paradigm ;
                                  orkgp:P56008 ?data_collection .

                    ?venue rdfs:label ?venue_name .

                    ?research_paradigm rdfs:label ?research_paradigmLabel .

                    ?data_collection rdfs:label ?dc_label ;
                                     orkgp:DATA ?research_data ;
                                     orkgp:P1005 ?dc_method .

                    ?research_data orkgp:P7055 ?data_type .
                    ?data_type rdfs:label ?data_typeLabel .

                    ?dc_method orkgp:P94003 ?method_type .
                    ?method_type rdfs:label ?method_typeLabel .

                    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
                    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

                    FILTER(?dc_label != "no collection"^^xsd:string)
                    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
                    FILTER(
                        ?data_typeLabel = "qualitative"^^xsd:string ||
                        ?data_typeLabel = "quantitative"^^xsd:string
                    )
                }
                GROUP BY ?decade ?data_type ?data_typeLabel
                         ?research_paradigm ?research_paradigmLabel
                         ?method_type ?method_typeLabel
            }
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
    }

    {
        SELECT ?decade ?data_type ?data_typeLabel
               ?research_paradigm ?research_paradigmLabel
               ?method_type ?method_typeLabel
               (COUNT(DISTINCT ?paper) AS ?paper_count)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm ;
                          orkgp:P56008 ?data_collection .

            ?venue rdfs:label ?venue_name .

            ?research_paradigm rdfs:label ?research_paradigmLabel .

            ?data_collection rdfs:label ?dc_label ;
                             orkgp:DATA ?research_data ;
                             orkgp:P1005 ?dc_method .

            ?research_data orkgp:P7055 ?data_type .
            ?data_type rdfs:label ?data_typeLabel .

            ?dc_method orkgp:P94003 ?method_type .
            ?method_type rdfs:label ?method_typeLabel .

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
            BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

            FILTER(?dc_label != "no collection"^^xsd:string)
            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
            FILTER(
                ?data_typeLabel = "qualitative"^^xsd:string ||
                ?data_typeLabel = "quantitative"^^xsd:string
            )
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
                 ?research_paradigm ?research_paradigmLabel
                 ?method_type ?method_typeLabel
    }

    FILTER(?paper_count = ?max_paper_count)
}
ORDER BY ?decade ?data_typeLabel DESC(?paper_count) ?research_paradigmLabel ?method_typeLabel
